#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e6+5;
int n,Q,a[N],bel[N];
struct SegTree{
    int up,a[N],s[N],t[N];
    int ls(int x){return (x<<1);}
    int rs(int x){return (x<<1|1);}
    void push_up(int x){s[x]=s[ls(x)]+s[rs(x)];return;}
    void build(int x,int l,int r){
        if(l==r){s[x]=a[l],t[x]=0;return;}
        int mid=(l+r)>>1;
        build(ls(x),l,mid);build(rs(x),mid+1,r);
        push_up(x);return;
    }
    void push_down(int x,int l,int r){
        if(!t[x])return;
        t[ls(x)]^=1,t[rs(x)]^=1;
        int mid=(l+r)>>1;
        s[ls(x)]=(mid-l+1)-s[ls(x)];
        s[rs(x)]=(r-mid)-s[rs(x)];
        t[x]=0;return;
    }
    void change(int x,int l,int r,int L,int R){
        if(r<L||R<l)return;
        if(L<=l&&r<=R){s[x]=(r-l+1)-s[x],t[x]^=1;return;}
        push_down(x,l,r);
        int mid=(l+r)>>1;
        change(ls(x),l,mid,L,R);
        change(rs(x),mid+1,r,L,R);
        push_up(x);return;
    }
    LL ask(int x,int l,int r,int L,int R){
        if(r<L||R<l)return 0;
        if(L<=l&&r<=R)return s[x];
        push_down(x,l,r);
        int mid=(l+r)>>1;
        return ask(ls(x),l,mid,L,R)+ask(rs(x),mid+1,r,L,R);
    }
}SegT[7];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read(),Q=read();
    for(int i=1;i<=n;i++){
        int x=read();
        bel[i]=(!(i%6)?6:(i%6));
        SegT[bel[i]].a[++SegT[bel[i]].up]=x;
    }
    for(int i=1;i<=6;i++)
        SegT[i].up=n/i+((n%i)<=i),
        SegT[i].build(1,1,SegT[i].up);
    while(Q--){
        int opt=read(),x=read(),y=read();
        if(opt==1){
            int ys=(x%6);
            for(int c=1;c<=3;c++,ys=(ys+2)%6){
                int st=x;
                while(st%6!=ys&&st<=y)st++;
                if(st>y)continue;
                int ed=y;
                while(ed%6!=ys&&ed>st)ed--;
                if(!ys)ys=6;
                //cout<<st<<","<<ed<<"\n";
                st=(st+5)/6,ed=(ed+5)/6;
                //cout<<st<<" "<<ed<<" -- "<<ys<<"\n\n";
                SegT[ys].change(1,1,SegT[ys].up,st,ed);
            }
        }else if(opt==2){
            int ys=(x%6);
            for(int c=1;c<=2;c++,ys=(ys+3)%6){
                int st=x;
                while(st%6!=ys&&st<=y)st++;
                if(st>y)continue;
                int ed=y;
                while(ed%6!=ys&&ed>st)ed--;
                if(!ys)ys=6;
                st=(st+5)/6,ed=(ed+5)/6;
                SegT[ys].change(1,1,SegT[ys].up,st,ed);
            }
        }else if(opt==3){
            int ys=(x%6);
            for(int c=1;c<=6;c++,ys=(ys+1)%6){
                int st=x;
                while(st%6!=ys&&st<=y)st++;
                if(st>y)continue;
                int ed=y;
                while(ed%6!=ys&&ed>st)ed--;
                if(!ys)ys=6;
                st=(st+5)/6,ed=(ed+5)/6;
                SegT[ys].change(1,1,SegT[ys].up,st,ed);
            }
        }else{
            int res=0,ys=(x%6);
            for(int c=1;c<=6;c++,ys=(ys+1)%6){
                int st=x;
                while(st%6!=ys&&st<=y)st++;
                if(st>y)continue;
                int ed=y;
                while(ed%6!=ys&&ed>st)ed--;
                if(!ys)ys=6;
                st=(st+5)/6,ed=(ed+5)/6;
                //cout<<SegT[ys].ask(1,1,SegT[ys].up,st,ed)<<"++"<<ys<<".\n";
                res+=SegT[ys].ask(1,1,SegT[ys].up,st,ed);
            }cout<<res<<"\n";
        }
    }
    return 0;
}
